import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

public class DateTimeUtils {
    public static boolean isAfterCurrentDateTime(String targetDateTime) {
        // 指定された日時をLocalDateTimeオブジェクトに変換
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
        LocalDateTime target = LocalDateTime.parse(targetDateTime, formatter);

        // 現在の日時を取得
        LocalDateTime now = LocalDateTime.now();

        // 比較結果を返す
        return now.isAfter(target);
    }
}

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

public class DateTimeUtils {
    public static String calculateDateTimeAfterNSeconds(String baseDateTime, int seconds) {
        // 指定された日時をLocalDateTimeオブジェクトに変換
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
        LocalDateTime base = LocalDateTime.parse(baseDateTime, formatter);

        // N秒後の時刻を計算
        LocalDateTime result = base.plusSeconds(seconds);

        // 計算結果を文字列に変換して返す
        return result.format(formatter);
    }
}

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;

public class DateTimeUtils {
    public static long calculateIntervalInSeconds(String dateTime1, String dateTime2) {
        // 指定された日時をLocalDateTimeオブジェクトに変換
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
        LocalDateTime dt1 = LocalDateTime.parse(dateTime1, formatter);
        LocalDateTime dt2 = LocalDateTime.parse(dateTime2, formatter);

        // 二つの日時間の間隔を秒で計算
        return ChronoUnit.SECONDS.between(dt1, dt2);
    }
}

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;

public class DateUtils {
    public static long calculateDaysBetween(String date1, String date2) {
        // 指定された日時をLocalDateオブジェクトに変換
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd");
        LocalDate d1 = LocalDate.parse(date1, formatter);
        LocalDate d2 = LocalDate.parse(date2, formatter);

        // 二つの日付間の差を日数で計算
        return ChronoUnit.DAYS.between(d1, d2);
    }
}

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;

public class DateTimeUtils {
    public static void printRemainingTime(String futureDateTime) {
        // 指定された日時をLocalDateTimeオブジェクトに変換
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
        LocalDateTime futureDt = LocalDateTime.parse(futureDateTime, formatter);
        LocalDateTime now = LocalDateTime.now();

        // 現在から特定の日時までの残り時間を計算
        long hours = ChronoUnit.HOURS.between(now, futureDt);
        long minutes = ChronoUnit.MINUTES.between(now.plusHours(hours), futureDt);
        long seconds = ChronoUnit.SECONDS.between(now.plusHours(hours).plusMinutes(minutes), futureDt);

        // 残り時間を表示
        System.out.println("Remaining time: " + hours + " hours " + minutes + " minutes " + seconds + " seconds");
    }
}

