import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.time.Duration;

public class DateTimeUtils {
    public static void printTotalSeconds(String startDateTime, String endDateTime) {
        // 指定された日時をLocalDateTimeオブジェクトに変換
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
        LocalDateTime start = LocalDateTime.parse(startDateTime, formatter);
        LocalDateTime end = LocalDateTime.parse(endDateTime, formatter);

        // 二つの日時間隔の差分を秒で計算
        Duration duration = Duration.between(start, end);
        long seconds = duration.getSeconds();

        // 総秒数を表示
        System.out.println("Total seconds: " + seconds);
    }
}

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;

public class DateTimeUtils {
    public static void printDateAfterNDays(String date, int days) {
        // 指定された日付をLocalDateオブジェクトに変換
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd");
        LocalDate localDate = LocalDate.parse(date, formatter);

        // 指定された日数を加算
        LocalDate resultDate = localDate.plusDays(days);

        // n日後の日付を表示
        System.out.println("Date after " + days + " days: " + resultDate);
    }
}

import java.time.LocalDate;
import java.time.DayOfWeek;
import java.time.format.DateTimeFormatter;
import java.util.HashMap;
import java.util.Map;

public class DateTimeUtils {
    public static void printDaysCount(String startDate, String endDate) {
        // 文字列をLocalDateに変換
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd");
        LocalDate start = LocalDate.parse(startDate, formatter);
        LocalDate end = LocalDate.parse(endDate, formatter);

        Map<DayOfWeek, Integer> countMap = new HashMap<>();

        // 開始日から終了日までループ
        for (LocalDate date = start; !date.isAfter(end); date = date.plusDays(1)) {
            // 曜日を取得し、カウントマップに追加
            DayOfWeek dayOfWeek = date.getDayOfWeek();
            countMap.put(dayOfWeek, countMap.getOrDefault(dayOfWeek, 0) + 1);
        }

        // 各曜日のカウントを出力
        for (DayOfWeek dayOfWeek : DayOfWeek.values()) {
            System.out.println(dayOfWeek + ": " + countMap.getOrDefault(dayOfWeek, 0));
        }
    }
}

import java.time.LocalTime;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;

public class DateTimeUtils {
    public static int differenceInMinutes(String time1, String time2) {
        // 文字列をLocalTimeに変換
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("HH:mm");
        LocalTime localTime1 = LocalTime.parse(time1, formatter);
        LocalTime localTime2 = LocalTime.parse(time2, formatter);

        // 2つの時間の差（分）を計算
        long difference = ChronoUnit.MINUTES.between(localTime1, localTime2);

        return (int)difference;
    }
}
